                                                <p className="text-white font-bold">${order.total_amount.toFixed(2)} USD</p>
                                                <p className="text-xs text-gray-500 mt-1">{new Date(order.created_at).toLocaleDateString()}</p>
                                            </div>

                                            <div className="flex -space-x-3">
                                                {/* Mostrar miniaturas de los items comprados */}
                                                {(order.cart_items as any[]).slice(0, 4).map((item: any, idx: number) => (
                                                    <img key={idx} src={item.image} alt={item.name} className="w-10 h-10 rounded-full border border-gray-600 object-cover relative" style={{ zIndex: 10 - idx }} title={item.name} />
                                                ))}
                                                {(order.cart_items as any[]).length > 4 && (
                                                    <div className="w-10 h-10 rounded-full border border-gray-800 bg-gray-900 flex items-center justify-center text-xs text-gray-400 relative" style={{ zIndex: 1 }}>
                                                        +{(order.cart_items as any[]).length - 4}
                                                    </div>
                                                )}
                                            </div>

                                            <div>
                                                <span className="px-3 py-1 bg-green-900/30 text-green-500 text-xs border border-green-800 rounded-full">Completado</span>
                                            </div>
                                        </div>
                                    ))}
                                </div>
                            ) : (
                                <div className="text-center py-10 text-gray-500">
                                    <div className="w-16 h-16 bg-gray-900 rounded-full flex items-center justify-center mx-auto mb-4 border border-gray-800">
                                        <i className="fas fa-box-open text-2xl"></i>
                                    </div>
                                    <p className="font-medium text-white mb-1">Aún no tienes pedidos registrados</p>
                                    <p className="text-xs">Tus compras futuras se listarán cronológicamente aquí.</p>
                                </div>
                            )}
                        </div>

                        {/* Favoritos */}
                        <div className="bg-[#111] border border-gray-800 rounded-lg p-8 text-center text-gray-500">
                            <i className="far fa-heart text-3xl mb-3"></i>
                            <p className="text-sm">Aún no tienes items en tu lista de deseos.</p>
                            <button className="mt-4 text-grecia-accent hover:text-white transition text-sm">Explorar Catálogo</button>
                        </div>
                    </div>
                </div>
            </div>
        </main>
    );
}

"use client";

import { useAppContext } from "@/context/AppContext";
import { useState } from "react";
import { PayPalScriptProvider, PayPalButtons } from "@paypal/react-paypal-js";

interface CartSidebarProps {
    isOpen: boolean;
    onClose: () => void;
}

export default function CartSidebar({ isOpen, onClose }: CartSidebarProps) {
    const { cart, removeFromCart, updateCartItemQuantity, clearCart, user } = useAppContext();
    const [isStripeLoading, setIsStripeLoading] = useState(false);

    const subtotal = cart.reduce((total, item) => total + item.price * item.quantity, 0);

    // ---------------------------------------------
    // 1. MANEJADOR DE PAGO STRIPE (Redirección)
    // ---------------------------------------------
    const handleStripeCheckout = async () => {
        if (cart.length === 0) return;
        setIsStripeLoading(true);

        try {
            // Llamar a nuestra API Route Backend
            const response = await fetch('/api/checkout_sessions', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({
                    items: cart,
                    customerEmail: user?.email, // Si está logueado, pre-llenar email en Stripe
                    userId: user?.id, // Enviar ID de Supabase
                    destinationUrl: window.location.origin
                }),
            });

            const session = await response.json();

            if (session.error) throw new Error(session.error);

            // Redirigir la ventana a la página segura de Stripe Hosted Checkout usando la URL provista por el Server
            if (session.url) {
                window.location.href = session.url;
            } else {
                throw new Error("El servidor de Stripe no retornó una URL válida de pago.");
            }
        } catch (error) {
            console.error(error);
            alert("Ocurrió un error al conectar con el servidor de pagos (Stripe).");
        } finally {
            setIsStripeLoading(false);
        }
    };

    // ---------------------------------------------
    // 2. MANEJADORES DE PAGO PAYPAL (Modal Popup)
    // ---------------------------------------------
    const createPayPalOrder = async () => {
        try {
            // Llamar a nuestro Backend para estampar la orden segura
            const response = await fetch("/api/paypal/create-order", {
                method: "POST",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify({ items: cart }),
            });

            const order = await response.json();
            if (order.id) {
                return order.id;
            } else {
                const errorDetail = order?.details?.[0];
                const errorMessage = errorDetail ? `${errorDetail.issue} ${errorDetail.description} (${order.debug_id})` : JSON.stringify(order);
                throw new Error(errorMessage);
            }
        } catch (error) {
            console.error(error);
            alert("No se pudo iniciar PayPal");
        }
    };

    const onPayPalApprove = async (data: any, actions: any) => {
        // En un Ecommerce real, aquí harías una llamada (fetch) a otra ruta tuya como `/api/paypal/capture-order`
        // para decirle a PayPal "Sí, ya vi que el cliente aceptó el cobro, quítale el dinero".
        // Por simplicidad en este prototipo, usamos las 'actions' directas:
        try {
            const capturedOrder = await actions.order.capture();
            if (capturedOrder.status === 'COMPLETED') {
                // Éxito Total
                clearCart();
                window.location.href = `/checkout/success?session_id=${capturedOrder.id}&gateway=paypal`;
            }
        } catch (error) {
            console.error("Fallo al cobrar la orden", error);
            alert("Fallo al cobrar la orden de PayPal.");
        }
    };

    const handleWhatsAppCheckout = () => {
        if (cart.length === 0) return;
        const phone = "1234567890"; // Reemplazar
        let message = "Hola Grecia Fashion Store! 👋%0AQuiero realizar el siguiente pedido manual:%0A%0A";
        cart.forEach((item, index) => {
            message += `${index + 1}. *${item.name}* (${item.quantity}x)%0A`;
        });
        message += `%0A*Total: $${subtotal.toFixed(2)}*%0A`;
        window.open(`https://wa.me/${phone}?text=${message}`, '_blank');
        clearCart();
        onClose();
    };

    return (
        <>
            <div id="cart-sidebar" className={`fixed inset-y-0 right-0 w-full md:w-[450px] bg-black border-l border-gray-800 shadow-2xl z-[70] transform transition-transform duration-300 flex flex-col ${isOpen ? "translate-x-0" : "translate-x-full"}`}>
                <div className="p-6 border-b border-gray-800 flex justify-between items-center bg-[#0a0a0a]">
                    <h2 className="font-serif text-lg font-bold text-white flex items-center gap-2">
                        <i className="fas fa-shopping-bag text-grecia-accent"></i> Tu Bolsa de Compras
                    </h2>
                    <button onClick={onClose} className="text-gray-400 hover:text-white transition bg-gray-900 w-8 h-8 rounded-full flex items-center justify-center">
                        <i className="fas fa-times"></i>
                    </button>
                </div>

                {/* Área Scroll de Ítems */}
                <div className="flex-1 overflow-y-auto p-6 bg-[#050505]">
                    {cart.length === 0 ? (
                        <div className="h-full flex flex-col items-center justify-center text-gray-500 opacity-50">
                            <i className="fas fa-shopping-basket text-5xl mb-4"></i>
                            <p className="text-sm">Tu bolsa está vacía</p>
                            <p className="text-xs mt-2 text-center max-w-[200px]">Explora nuestro catálogo y añade tus prendas favoritas.</p>
                            <button onClick={onClose} className="mt-6 border border-gray-700 hover:border-grecia-accent hover:text-white text-xs px-6 py-2 rounded uppercase tracking-widest transition">
                                Volver a la Tienda
                            </button>
                        </div>
                    ) : (
                        <div className="space-y-6">
                            {cart.map((item) => (
                                <div key={item.id} className="flex gap-4 bg-[#111] border border-gray-900 p-3 rounded-lg relative group">
                                    <button
                                        onClick={() => removeFromCart(item.id)}
                                        className="absolute -top-2 -right-2 bg-red-900 border border-red-700 text-white w-6 h-6 rounded-full text-xs opacity-0 group-hover:opacity-100 transition shadow-lg z-10 hover:bg-red-600"
                                    >
                                        <i className="fas fa-times"></i>
                                    </button>

                                    {/* eslint-disable-next-line @next/next/no-img-element */}
                                    <img src={item.image} alt={item.name} className="w-20 h-24 object-cover rounded border border-gray-800" />

                                    <div className="flex-1 flex flex-col justify-between py-1">
                                        <div>
                                            <h3 className="text-white font-serif font-bold text-sm leading-tight pr-4">{item.name}</h3>
                                            <p className="text-[10px] text-grecia-accent uppercase tracking-wider mt-1">{item.category}</p>
                                        </div>

                                        <div className="flex items-end justify-between mt-2">
                                            <div className="flex items-center gap-3 bg-black border border-gray-800 rounded px-2 py-1">
                                                <button onClick={() => updateCartItemQuantity(item.id, item.quantity - 1)} className="text-gray-400 hover:text-white transition w-5 text-center">-</button>
                                                <span className="text-white text-xs font-bold w-4 text-center">{item.quantity}</span>
                                                <button onClick={() => updateCartItemQuantity(item.id, item.quantity + 1)} className="text-gray-400 hover:text-white transition w-5 text-center">+</button>
                                            </div>
                                            <span className="text-white font-bold text-sm">${(item.price * item.quantity).toFixed(2)}</span>
                                        </div>
                                    </div>
                                </div>
                            ))}
                        </div>
                    )}
                </div>

                {/* Zona de Cobro */}
                {cart.length > 0 && (
                    <div className="p-6 border-t border-gray-800 bg-[#0a0a0a]">
                        <div className="flex justify-between mb-2 text-sm text-gray-400">
                            <span>Subtotal:</span>
                            <span>${subtotal.toFixed(2)}</span>
                        </div>
                        <div className="flex justify-between mb-2 text-sm text-gray-400">
                            <span>Impuestos / Envío:</span>
                            <span className="text-green-500 font-bold">Por calcular</span>
                        </div>
                        <div className="flex justify-between mb-6 text-xl font-serif font-bold text-white border-t border-gray-800 pt-3 mt-3">
                            <span>Total estimado:</span>
                            <span className="text-grecia-accent">${subtotal.toFixed(2)}</span>
                        </div>

                        {/* Aviso de Recojo Exclusivo */}
                        <div className="bg-[#111] border border-gray-800 rounded p-3 mb-4 flex items-start gap-3">
                            <i className="fas fa-store text-grecia-accent mt-0.5"></i>
                            <p className="text-[11px] text-gray-300">
                                <span className="text-white font-bold opacity-100">Políticas de Entrega:</span> Todas las compras completadas a través de este medio son exclusivamente para <span className="text-white font-bold underline decoration-grecia-accent">recojo físico presencial en nuestra boutique</span>.
                            </p>
                        </div>

                        {/* Botonera de Pasarelas / Bloqueo por Sesión */}
                        {!user ? (
                            <div className="text-center bg-gray-900 border border-gray-800 rounded-lg p-5">
                                <i className="fas fa-lock text-gray-500 text-3xl mb-3"></i>
                                <p className="text-sm text-white font-bold mb-2 uppercase tracking-wide">Autenticación Requerida</p>
                                <p className="text-[11px] text-gray-400 mb-4 px-2">
                                    Para garantizar la máxima seguridad transaccional, debes iniciar sesión o crear una cuenta de cliente para poder procesar tu pago.
                                </p>
                                <button
                                    onClick={() => {
                                        onClose();
                                        // Truco: Hacer click automatizado en el ícono de login del Header
                                        document.getElementById('user-icon')?.click();
                                    }}
                                    className="w-full bg-white text-black py-3 font-bold hover:bg-gray-200 transition text-xs uppercase tracking-widest rounded"
                                >
                                    Iniciar Sesión / Registrarse
                                </button>
                            </div>
                        ) : (
                            <div className="space-y-3">
                                {/* Stripe (Tarjetas, Apple Pay, Google Pay) */}
                                <button
                                    onClick={handleStripeCheckout}
                                    disabled={isStripeLoading}
                                    className="w-full bg-[#635BFF] text-white py-3.5 font-bold hover:bg-[#5249DE] transition flex items-center justify-center gap-2 shadow-lg rounded hover:shadow-[#635BFF]/30 disabled:opacity-50 text-sm"
                                >
                                    {isStripeLoading ? (
                                        <i className="fas fa-spinner fa-spin"></i>
                                    ) : (
                                        <>
                                            <i className="fas fa-credit-card text-lg"></i> Pagar Seguro con Stripe
                                        </>
                                    )}
                                </button>

                                {/* PayPal Oculto Temporalmente por Petición del Cliente */}
                                {/* 
                                <div className="relative z-0 mt-2 min-h-[45px]">
                                    <PayPalScriptProvider options={{
                                        clientId: process.env.NEXT_PUBLIC_PAYPAL_CLIENT_ID || "sb",
                                        currency: "USD",
                                        components: "buttons"
                                    }}>
                                        <PayPalButtons
                                            createOrder={createPayPalOrder}
                                            onApprove={onPayPalApprove}
                                            style={{ layout: "vertical", color: "gold", shape: "rect", height: 45 }}
                                        />
                                    </PayPalScriptProvider>
                                </div> 
                                */}

                                {/* Divider Visual */}
                                <div className="flex items-center my-5 opacity-50">
                                    <div className="flex-1 h-px bg-gray-700"></div>
                                    <span className="px-3 text-[10px] text-gray-400 uppercase tracking-widest">O cordina sin pago</span>
                                    <div className="flex-1 h-px bg-gray-700"></div>
                                </div>

                                {/* Compra Manual Whatsapp (Backup) */}
                                <button
                                    onClick={handleWhatsAppCheckout}
                                    className="w-full bg-transparent border border-gray-700 text-gray-300 py-2.5 hover:bg-[#25D366] hover:text-white hover:border-[#25D366] transition flex items-center justify-center gap-2 rounded text-[11px] uppercase tracking-widest"
                                >
                                    <i className="fab fa-whatsapp text-sm"></i> Reservar vía WhatsApp
                                </button>
                            </div>
                        )}

                        <p className="text-[10px] text-center text-gray-600 mt-5">
                            <i className="fas fa-shield-alt mr-1"></i> Transacciones encriptadas 256-bit SSL.
                        </p>
                    </div>
                )}
            </div>

            {/* Backdrop Negro */}
            {isOpen && (
                <div onClick={onClose} className="fixed inset-0 bg-black/80 z-[60] backdrop-blur-sm transition-opacity"></div>
            )}
        </>
    );
}

"use client";

import { useState } from "react";
import { useAppContext } from "@/context/AppContext";

export default function Store() {
    const { products, addToCart } = useAppContext();
    const [activeCategory, setActiveCategory] = useState<string>("Ver Todo");
    const [selectedImage, setSelectedImage] = useState<string | null>(null);

    const handleAddToCart = (product: any) => {
        addToCart(product);
        // Opcional: Feedback visual rápido
    };

    // Extraer categorías únicas dinámicamente, más la de "Ver Todo"
    const categoriesSet = new Set(products.map(p => p.category));
    const categories = ["Ver Todo", ...Array.from(categoriesSet)];

    // Filtrar los productos para el render principal
    const filteredProducts = activeCategory === "Ver Todo"
        ? products
        : products.filter(p => p.category === activeCategory);

    return (
        <section id="store" className="py-20 bg-[#050505] min-h-screen border-t border-gray-900">
            <div className="container mx-auto px-6">
                <div className="text-center mb-12">
                    <span className="text-grecia-accent text-[10px] md:text-xs tracking-[0.3em] font-bold uppercase flex items-center justify-center gap-3 mb-3">
                        <span className="w-8 h-[1px] bg-grecia-accent/50"></span> Explorar Colecciones <span className="w-8 h-[1px] bg-grecia-accent/50"></span>
                    </span>
                    <h2 className="text-4xl md:text-5xl font-serif font-light mt-2 text-white tracking-wide">
                        Nuestro <span className="italic text-gray-400 font-medium">Catálogo</span>
                    </h2>
                </div>

                {/* Filtro de Categorías */}
                <div className="flex flex-wrap justify-center gap-2 mb-16 max-w-4xl mx-auto">
                    {categories.map(cat => (
                        <button
                            key={cat}
                            onClick={() => setActiveCategory(cat)}
                            className={`px-6 py-2.5 rounded-full text-[10px] sm:text-xs uppercase tracking-widest transition-all duration-300 ${activeCategory === cat
                                ? 'bg-grecia-accent text-white font-bold shadow-[0_5px_15px_rgba(221,167,165,0.4)] tracking-[0.2em]'
                                : 'bg-[#111] text-gray-400 font-medium hover:bg-[#1a1a1a] hover:text-white border border-gray-800'
                                }`}
                        >
                            {cat}
                        </button>
                    ))}
                </div>

                <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-x-8 gap-y-12">
                    {filteredProducts.map((product) => {
                        const isOutOfStock = product.stock <= 0;

                        return (
                            <div key={product.id} className="group relative transition duration-[1.5s] animate-fade-in-up flex flex-col">
                                <div className="relative overflow-hidden mb-5 bg-[#0a0a0a] aspect-[3/4] rounded-[2rem] shadow-xl hover:shadow-[0_20px_40px_rgba(221,167,165,0.08)] transition-all duration-700">
                                    {/* eslint-disable-next-line @next/next/no-img-element */}
                                    <img src={product.image} alt={product.name} className={`w-full h-full object-cover transition duration-[1.5s] ease-[cubic-bezier(0.16,1,0.3,1)] ${isOutOfStock ? 'grayscale opacity-30' : 'group-hover:scale-105 opacity-90 group-hover:opacity-100'}`} />

                                    <div className="absolute inset-0 bg-black/5 group-hover:bg-[#4a2e2d]/20 transition duration-700 z-10 pointer-events-none mix-blend-multiply"></div>
                                    <div className="absolute inset-0 bg-gradient-to-t from-[#0a0a0a]/80 via-transparent to-transparent opacity-0 group-hover:opacity-100 transition duration-700 z-10 pointer-events-none"></div>

                                    {/* BADGES METADATA DATABASE */}
                                    {isOutOfStock ? (
                                        <div className="absolute inset-x-0 bottom-6 flex items-center justify-center z-10 animate-pulse">
                                            <span className="bg-red-900/90 backdrop-blur-md text-red-100 px-6 py-2 text-[10px] font-bold tracking-[0.2em] uppercase rounded-full border border-red-500/30 shadow-2xl">
                                                Agotado
                                            </span>
                                        </div>
                                    ) : (
                                        <div className="absolute top-5 left-5 flex flex-col gap-2 z-20 items-start">
                                            {product.stock > 0 && product.stock <= 5 && (
                                                <div className="bg-grecia-accent/90 backdrop-blur-md text-white text-[9px] font-bold px-4 py-1.5 uppercase tracking-[0.2em] shadow-[0_5px_15px_rgba(221,167,165,0.4)] rounded-full">
                                                    ÚLTIMAS {product.stock}
                                                </div>
                                            )}
                                            {product.is_bestseller && (
                                                <div className="bg-[#DDA7A5]/90 backdrop-blur-md text-black text-[9px] font-bold px-4 py-1.5 uppercase tracking-[0.15em] shadow-[0_5px_15px_rgba(221,167,165,0.4)] rounded-full flex items-center">
                                                    <i className="fas fa-crown text-black/70 mr-1.5"></i> Best Seller
                                                </div>
                                            )}
                                            {product.is_new && (
                                                <div className="bg-white/90 backdrop-blur-md text-black text-[9px] font-bold px-4 py-1.5 uppercase tracking-[0.15em] shadow-[0_5px_15px_rgba(255,255,255,0.4)] rounded-full flex items-center">
                                                    ✨ Nuevo
                                                </div>
                                            )}
                                            {product.is_offer && (
                                                <div className="bg-red-500/90 backdrop-blur-md text-white text-[9px] font-bold px-4 py-1.5 uppercase tracking-[0.15em] shadow-[0_5px_15px_rgba(239,68,68,0.4)] rounded-full flex items-center">
                                                    Sale %
                                                </div>
                                            )}
                                        </div>
                                    )}

                                    {!isOutOfStock && (
                                        <div className="absolute inset-x-0 bottom-0 p-5 opacity-0 group-hover:opacity-100 transform translate-y-6 group-hover:translate-y-0 transition-all duration-700 ease-[cubic-bezier(0.16,1,0.3,1)] z-20 flex flex-col gap-2">
                                            <button
                                                onClick={() => setSelectedImage(product.image)}
                                                className="bg-[#111]/90 backdrop-blur-md text-white w-full py-2.5 font-bold text-[9px] uppercase tracking-[0.15em] hover:bg-white hover:text-black border border-white/20 transition-all duration-500 rounded-full flex items-center justify-center gap-2">
                                                <i className="fas fa-search-plus"></i> Ver Tamaño Real
                                            </button>
                                            <button
                                                onClick={() => handleAddToCart(product)}
                                                className="bg-white/95 backdrop-blur-md text-black w-full py-3.5 font-bold text-[10px] uppercase tracking-[0.15em] hover:bg-grecia-accent hover:text-white border border-transparent transition-all duration-500 shadow-[0_15px_30px_rgba(0,0,0,0.3)] hover:shadow-[0_15px_30px_rgba(221,167,165,0.4)] rounded-full">
                                                Agregar a la Bolsa
                                            </button>
                                        </div>
                                    )}
                                </div>

                                <div className="text-center px-1 flex-grow flex flex-col justify-between">
                                    <div>
                                        <h3 className="font-sans font-medium text-gray-200 text-sm md:text-[15px] mb-1 hover:text-white cursor-pointer transition tracking-wide">{product.name}</h3>

                                        {/* SOCIAL PROOF / REVIEWS (Idea 3) */}
                                        <div className="flex justify-center items-center gap-1 mb-2">
                                            <div className="flex text-[#FFC107] text-[9px]">
                                                <i className="fas fa-star"></i>
                                                <i className="fas fa-star"></i>
                                                <i className="fas fa-star"></i>
                                                <i className="fas fa-star"></i>
                                                <i className="fas fa-star-half-alt"></i>
                                            </div>
                                            <span className="text-[10px] text-gray-500 ml-1">(4.9)</span>
                                        </div>

                                        <div className="flex justify-center items-center gap-3 mb-3">
                                            <span className="text-white font-serif italic text-lg">${product.price}</span>
                                            {/* <p className="text-[#D2B48C] font-serif italic text-lg opacity-90">${product.price}</p> */} {/* This line was commented out as it seemed like a duplicate price display */}
                                        </div>
                                    </div>

                                    <div>
                                        {/* Swatches de Color Reales desde DB */}
                                        {product.colors && product.colors.length > 0 && (
                                            <div className="flex justify-center items-center gap-2 mb-3">
                                                {product.colors.map(colorHex => (
                                                    <div
                                                        key={colorHex}
                                                        className={`w-3.5 h-3.5 rounded-full border border-gray-700/50 shadow-inner`}
                                                        style={{ backgroundColor: colorHex }}
                                                        title="Opción de color"
                                                    ></div>
                                                ))}
                                            </div>
                                        )}

                                        {/* GUÍA DE TALLAS COLOMBIANA (Idea 5) */}
                                        <div className="flex flex-col items-center gap-1 mt-1">
                                            <span className="text-[9px] text-gray-500 uppercase tracking-[0.2em]">{product.category}</span>
                                            <span className="text-[10px] text-grecia-accent hover:text-white cursor-pointer transition mt-0.5 border-b border-dashed border-grecia-accent/30 hover:border-white">
                                                <i className="fas fa-ruler-combined mr-1"></i> Guía de Tallas (Horma Pequeña)
                                            </span>
                                        </div>
                                    </div>
                                </div>
                            </div>
                        );
                    })}
                </div>
            </div>

            {/* MODAL DE IMAGEN COMPLETA (LIGHTBOX) */}
            {selectedImage && (
                <div className="fixed inset-0 z-[100] flex items-center justify-center bg-black/95 backdrop-blur-xl p-4 md:p-12 animate-fade-in-up">
                    <button
                        onClick={() => setSelectedImage(null)}
                        className="absolute top-6 right-6 md:top-10 md:right-10 text-white/50 hover:text-white transition bg-black/50 w-12 h-12 rounded-full flex items-center justify-center"
                    >
                        <i className="fas fa-times text-2xl"></i>
                    </button>
                    <div className="relative w-full h-full max-w-5xl max-h-[85vh] rounded-[2rem] overflow-hidden shadow-[0_0_50px_rgba(221,167,165,0.15)] bg-[#050505]">
                        {/* eslint-disable-next-line @next/next/no-img-element */}
                        <img
                            src={selectedImage}
                            alt="Vista Ampliada"
                            className="w-full h-full object-contain"
                        />
                    </div>
                </div>
            )}
        </section>
    );
}

"use client";

import { useState, useEffect } from "react";
import Link from "next/link";
import { useRouter } from "next/navigation";
import { useAppContext } from "@/context/AppContext";
import CartSidebar from "@/components/cart/CartSidebar";
import { createClient } from "@/utils/supabase/client";

export default function Header() {
  const router = useRouter();
  const [mobileMenuOpen, setMobileMenuOpen] = useState(false);
  const [cartOpen, setCartOpen] = useState(false);
  const [loginModalOpen, setLoginModalOpen] = useState(false);
  const [isLoginMode, setIsLoginMode] = useState(true);
  const [isScrolled, setIsScrolled] = useState(false);

  useEffect(() => {
    const handleScroll = () => {
      setIsScrolled(window.scrollY > 30);
    };
    window.addEventListener("scroll", handleScroll);
    return () => window.removeEventListener("scroll", handleScroll);
  }, []);

  // Estados Globales Simulación Login y Carrito
  const { user, userRole, setUserRole, cart } = useAppContext();

  const cartCount = cart.reduce((total, item) => total + item.quantity, 0);

  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [phone, setPhone] = useState("");
  const [loginError, setLoginError] = useState("");
  const [acceptTerms, setAcceptTerms] = useState(false);

  const handleAuthSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoginError("");

    try {
      const supabase = createClient();

      if (!isLoginMode) {
        // Registro
        const { data, error } = await supabase.auth.signUp({
          email,
          password,
        });

        if (error) {
          setLoginError(error.message);
        } else {
          setLoginError("✅ ¡Registro exitoso! Por favor revisa tu correo.");
          setIsLoginMode(true);
        }
        return;
      }

      // Login
      const { data, error } = await supabase.auth.signInWithPassword({
        email,
        password,
      });

      if (error || !data.user) {
        setLoginError("Credenciales incorrectas o servidor fallando.");
        return;
      }

      // Login Exitoso (Cookies ya fueron seteadas por Supabase JS)
      const role = data.user.email === 'greciafashionstore2@gmail.com' ? 'admin' : 'user';
      setUserRole(role);

      setLoginModalOpen(false);
      setEmail("");
      setPassword("");
      setPhone("");

      // Redirección Automática con Refresco de Estado (Hard Navigate)
      if (role === 'admin') {
        window.location.href = '/admin';
      } else {
        window.location.href = '/';
      }
    } catch {
      setLoginError("Error conectando con el servidor local.");
    }
  };

  const handleGoogleLogin = async () => {
    try {
      const supabase = createClient();
      const { error } = await supabase.auth.signInWithOAuth({
        provider: 'google',
        options: {
          redirectTo: `${window.location.origin}/api/auth/callback`
        }
      });
      if (error) throw error;
    } catch {
      setLoginError("Error inicializando sesión con Google.");
    }
  };

  const handleLogout = async () => {
    try {
      const supabase = createClient();
      await supabase.auth.signOut();
      setUserRole(null);
      window.location.href = '/';
    } catch {
      console.error("Error cerrando sesión local");
    }
  };

  return (
    <>
      <header className={`fixed w-full top-0 z-40 transition-all duration-700 ${isScrolled ? "bg-black/98 border-b border-gray-900 backdrop-blur-xl shadow-2xl" : "bg-gradient-to-b from-black/80 via-black/40 to-transparent"}`}>

        {/* Top Banner (Desaparece al Scrollear) */}
        <div className={`bg-grecia-accent text-white flex justify-between items-center font-medium tracking-wider uppercase transition-all duration-500 overflow-hidden ${isScrolled ? "h-0 opacity-0" : "h-8 md:h-10 px-4 opacity-100"}`}>
          <div className="hidden md:flex gap-4">
            <a href="https://www.instagram.com/greciafashionstore/" target="_blank" rel="noopener noreferrer" className="hover:text-black transition text-xs">
              <i className="fab fa-instagram"></i>
            </a>
            <a href="https://www.facebook.com/GreciaFashionStore" target="_blank" rel="noopener noreferrer" className="hover:text-black transition text-xs">
              <i className="fab fa-facebook-f"></i>
            </a>
          </div>
          <div className="mx-auto md:mx-0 text-[10px] md:text-[11px]">
            🚚 Envíos rápidos y seguros en New Jersey
          </div>
        </div>

        {/* Main Header Container */}
        <div className={`container mx-auto px-6 transition-all duration-500 flex items-center justify-between ${isScrolled ? "py-3" : "py-5"}`}>
          <button className="md:hidden text-white text-xl" onClick={() => setMobileMenuOpen(!mobileMenuOpen)}>
            <i className="fas fa-bars"></i>
          </button>

          <Link href="/" className="flex flex-col items-center group">
            <span className="text-2xl md:text-3xl font-serif font-bold transition-colors flex items-center gap-2">
              <span className="text-grecia-accent italic">Grecia</span>
              <span className="text-white">Fashion Store</span>
            </span>
            <span className="text-[9px] md:text-[10px] tracking-[0.4em] uppercase text-gray-400 mt-1">Boutique</span>
          </Link>

          <nav className="hidden md:flex space-x-8 items-center">
            <Link href="#categories" className="text-xs font-semibold text-gray-300 hover:text-grecia-accent tracking-widest uppercase transition">Líneas</Link>
            <Link href="#store" className="text-xs font-semibold text-grecia-accent hover:text-white tracking-widest uppercase transition">Catálogo</Link>
            <Link href="#testimonials" className="text-xs font-semibold text-gray-300 hover:text-grecia-accent tracking-widest uppercase transition">Reseñas</Link>
            <Link href="#visit-us" className="text-xs font-semibold text-gray-300 hover:text-grecia-accent tracking-widest uppercase transition">Visítanos</Link>
          </nav>

          <div className="flex items-center space-x-5">
            {userRole ? (
              <div className="flex items-center gap-4">
                {userRole === "admin" ? (
                  <span className="text-white text-xs hidden md:inline-block border border-gray-800 px-3 py-1 rounded">
                    Hola, <span className="text-grecia-accent font-bold">Admin</span>
                  </span>
                ) : (
                  <Link href="/user" className="text-white text-xs hidden md:inline-block border border-gray-800 px-3 py-1 rounded hover:border-grecia-accent transition" title="Mi Dashboard">
                    Hola, <span className="font-bold capitalize">{user?.full_name || user?.email?.split('@')[0] || "Cliente"}</span> <i className="fas fa-chevron-right text-[10px] ml-1"></i>
                  </Link>
                )}

                {userRole === "admin" && (
                  <Link href="/admin" className="text-grecia-accent hover:text-white transition text-sm flex items-center gap-1 bg-black/50 border border-gray-800 px-3 py-1 rounded-full cursor-pointer" title="Panel de Administrador">
                    <i className="fas fa-shield-alt text-xs"></i> Portal Admin
                  </Link>
                )}

                {userRole === "user" && (
                  <Link href="/user" className="text-gray-300 hover:text-white transition text-sm flex items-center gap-1 bg-black/50 border border-gray-800 px-3 py-1 rounded-full cursor-pointer" title="Mi Panel">
                    <i className="fas fa-user-circle text-xs"></i> Mi Perfil
                  </Link>
                )}

                <button onClick={handleLogout} className="text-gray-500 hover:text-red-500 transition text-sm flex items-center gap-1" title="Cerrar Sesión">
                  <i className="fas fa-sign-out-alt"></i>Salir
                </button>
              </div>
            ) : (
              <button onClick={() => setLoginModalOpen(true)} className="text-white hover:text-grecia-accent transition" title="Iniciar Sesión">
                <i className="fas fa-user text-xl" id="user-icon"></i>
              </button>
            )}

            <button className="text-white hover:text-grecia-accent transition relative group" onClick={() => setCartOpen(true)}>
              <i className="fas fa-shopping-bag text-xl"></i>
              {cartCount > 0 && (
                <span id="cart-count" className="absolute -top-1 -right-2 bg-grecia-accent text-white text-[10px] font-bold w-4 h-4 rounded-full flex items-center justify-center transform group-hover:scale-110 transition">
                  {cartCount > 99 ? '99+' : cartCount}
                </span>
              )}
            </button>
          </div>
        </div>

        {/* Mobile Menu */}
        <div className={`fixed inset-0 bg-black z-50 transform transition-transform duration-300 flex flex-col justify-center items-center space-y-8 md:hidden ${mobileMenuOpen ? "translate-x-0" : "-translate-x-full"}`}>
          <button className="absolute top-6 right-6 text-2xl text-white hover:text-grecia-accent" onClick={() => setMobileMenuOpen(false)}>
            <i className="fas fa-times"></i>
          </button>
          <Link href="#home" className="text-2xl font-serif text-white hover:text-grecia-accent transition" onClick={() => setMobileMenuOpen(false)}>Inicio</Link>
          <Link href="#categories" className="text-2xl font-serif text-white hover:text-grecia-accent transition" onClick={() => setMobileMenuOpen(false)}>Líneas</Link>
          <Link href="#store" className="text-2xl font-serif text-white hover:text-grecia-accent transition" onClick={() => setMobileMenuOpen(false)}>Catálogo</Link>
          <Link href="#testimonials" className="text-2xl font-serif text-white hover:text-grecia-accent transition" onClick={() => setMobileMenuOpen(false)}>Reseñas</Link>
          <Link href="#visit-us" className="text-2xl font-serif text-white hover:text-grecia-accent transition" onClick={() => setMobileMenuOpen(false)}>Visítanos</Link>

          {userRole ? (
            <div className="flex flex-col items-center gap-6 mt-4">
              {userRole === "admin" ? (
                <Link href="/admin" className="text-xl font-serif text-grecia-accent hover:text-white transition border-b border-gray-800 pb-2 flex items-center gap-2" onClick={() => setMobileMenuOpen(false)}>
                  <i className="fas fa-shield-alt"></i> Portal Admin
                </Link>
              ) : (
                <Link href="/user" className="text-xl font-serif text-white hover:text-grecia-accent transition border-b border-gray-800 pb-2 flex items-center gap-2" onClick={() => setMobileMenuOpen(false)}>
                  <i className="fas fa-user-circle"></i> Mi Perfil
                </Link>
              )}
              <button onClick={() => { handleLogout(); setMobileMenuOpen(false); }} className="text-lg font-serif text-red-500/80 hover:text-red-400 transition flex items-center gap-2">
                <i className="fas fa-sign-out-alt"></i> Cerrar Sesión
              </button>
            </div>
          ) : (
            <button onClick={() => { setLoginModalOpen(true); setMobileMenuOpen(false); }} className="text-2xl font-serif text-gray-400 hover:text-grecia-accent transition border border-gray-800 rounded px-8 py-3 mt-4">
              Iniciar Sesión Libre
            </button>
          )}
        </div>
      </header >



      {/* Login Modals */}
      {
        loginModalOpen && (
          <div className="fixed inset-0 z-[60] popup-overlay flex items-center justify-center p-4">
            <div className="bg-grecia-card border border-gray-800 rounded-lg shadow-2xl max-w-sm w-full p-8 relative animate-slide-up">
              <button onClick={() => setLoginModalOpen(false)} className="absolute top-4 right-4 text-gray-500 hover:text-white z-10 transition"><i className="fas fa-times text-xl"></i></button>
              <div className="text-center mb-6">
                <i className="fas fa-user-circle text-5xl text-white mb-4"></i>
                <h3 className="font-serif text-2xl font-bold text-white">
                  {isLoginMode ? "Bienvenido(a)" : "Crear Cuenta"}
                </h3>
                <p className="text-xs text-gray-400 mt-2">
                  {isLoginMode ? "Acceso seguro a clientes o administrador" : "Únete a nuestra exclusiva base de clientes"}
                </p>

                <div className="mt-4 p-3 bg-gray-900/50 rounded border border-gray-800 text-left">
                  <p className="text-[10px] text-gray-400 mb-1 font-bold">INFO DE SEGURIDAD:</p>
                  <p className="text-[10px] text-gray-500">🔒 Esta app ahora usa Criptografía Real de <span className="text-grecia-accent">Supabase Auth</span>.</p>
                  <p className="text-[10px] text-gray-500 mt-1">📧 El correo "admin@grecia.com" posee privilegios totales. Los demás correos registrados son clientes.</p>
                </div>
              </div>

              <form onSubmit={handleAuthSubmit} className="space-y-4">
                {loginError && (
                  <div className={`border text-xs p-2 rounded text-center ${loginError.includes('exitoso') ? 'bg-green-500/10 border-green-500/50 text-green-400' : 'bg-red-500/10 border-red-500/50 text-red-400'}`}>
                    {loginError}
                  </div>
                )}
                <input
                  type="email"
                  placeholder="Correo electrónico"
                  value={email}
                  onChange={(e) => setEmail(e.target.value)}
                  required
                  className="w-full bg-black border border-gray-800 text-white px-4 py-3 rounded focus:outline-none focus:border-grecia-accent transition"
                />
                {!isLoginMode && (
                  <input
                    type="tel"
                    placeholder="Número de Teléfono"
                    value={phone}
                    onChange={(e) => setPhone(e.target.value)}
                    required
                    className="w-full bg-black border border-gray-800 text-white px-4 py-3 rounded focus:outline-none focus:border-grecia-accent transition"
                  />
                )}
                <input
                  type="password"
                  placeholder="Contraseña segura"
                  value={password}
                  onChange={(e) => setPassword(e.target.value)}
                  required
                  className="w-full bg-black border border-gray-800 text-white px-4 py-3 rounded focus:outline-none focus:border-grecia-accent transition"
                />

                <div className="flex items-start gap-3 mt-4 bg-gray-900/40 p-3 rounded border border-gray-800">
                  <input
                    type="checkbox"
                    id="terms"
                    required
                    checked={acceptTerms}
                    onChange={(e) => setAcceptTerms(e.target.checked)}
                    className="mt-1 flex-shrink-0 w-4 h-4 accent-grecia-accent bg-black border-gray-700 rounded cursor-pointer"
                  />
                  <label htmlFor="terms" className="text-[10px] text-gray-400 leading-tight cursor-pointer">
                    Acepto los <span className="text-grecia-accent hover:underline">Términos y Condiciones</span>. Entiendo y estoy de acuerdo en que todas las compras realizadas en esta plataforma son estrictamente para <strong>recojo físico y presencial en la Boutique</strong> (Sin servicio de entrega a docimilio de terceros).
                  </label>
                </div>

                <button type="submit" className="w-full bg-grecia-accent text-white py-3 font-medium hover:bg-white hover:text-black transition shadow-[0_0_15px_rgba(255,42,122,0.4)] uppercase tracking-wider text-sm rounded mt-2">
                  {isLoginMode ? "Ingresar" : "Registrarse y Aceptar"}
                </button>
              </form>

              <div className="mt-4 mb-4 flex items-center justify-center">
                <div className="border-t border-gray-800 flex-grow"></div>
                <span className="mx-4 text-xs text-gray-500 uppercase">O continuar con</span>
                <div className="border-t border-gray-800 flex-grow"></div>
              </div>

              <button
                onClick={handleGoogleLogin}
                className="w-full bg-white text-black py-3 font-medium hover:bg-gray-200 transition shadow-sm rounded flex items-center justify-center gap-2 mb-4"
              >
                <svg width="18" height="18" xmlns="http://www.w3.org/2000/svg" viewBox="0 0 48 48">
                  <path fill="#FFC107" d="M43.611,20.083H42V20H24v8h11.303c-1.649,4.657-6.08,8-11.303,8c-6.627,0-12-5.373-12-12c0-6.627,5.373-12,12-12c3.059,0,5.842,1.154,7.961,3.039l5.657-5.657C34.046,6.053,29.268,4,24,4C12.955,4,4,12.955,4,24c0,11.045,8.955,20,20,20c11.045,0,20-8.955,20-20C44,22.659,43.862,21.35,43.611,20.083z" />
                  <path fill="#FF3D00" d="M6.306,14.691l6.571,4.819C14.655,15.108,18.961,12,24,12c3.059,0,5.842,1.154,7.961,3.039l5.657-5.657C34.046,6.053,29.268,4,24,4C16.318,4,9.656,8.337,6.306,14.691z" />
                  <path fill="#4CAF50" d="M24,44c5.166,0,9.86-1.977,13.409-5.192l-6.19-5.238C29.211,35.091,26.715,36,24,36c-5.202,0-9.619-3.317-11.283-7.946l-6.522,5.025C9.505,39.556,16.227,44,24,44z" />
                  <path fill="#1976D2" d="M43.611,20.083H42V20H24v8h11.303c-0.792,2.237-2.231,4.166-4.087,5.571c0.001-0.001,0.002-0.001,0.003-0.002l6.19,5.238C36.971,39.205,44,34,44,24C44,22.659,43.862,21.35,43.611,20.083z" />
                </svg>
                Google
              </button>

              <div className="text-center border-t border-gray-800 pt-4">
                <p className="text-xs text-gray-400">
                  {isLoginMode ? "¿No tienes cuenta? " : "¿Ya eres cliente? "}
                  <button
                    onClick={() => { setIsLoginMode(!isLoginMode); setLoginError(""); }}
                    className="text-grecia-accent font-bold hover:underline"
                  >
                    {isLoginMode ? "Regístrate aquí" : "Inicia Sesión"}
                  </button>
                </p>
              </div>
            </div>
          </div>
        )
      }

      {/* Componentes Flotantes */}
      <CartSidebar isOpen={cartOpen} onClose={() => setCartOpen(false)} />
      {/* <LoginModal isOpen={loginModalOpen} onClose={() => setLoginModalOpen(false)} /> */}
    </>
  );
}

"use client";

import { useRouter } from "next/navigation";
import { useAppContext } from "@/context/AppContext";

import { createClient } from "@/utils/supabase/client";

export default function LogoutButton() {
    const { setUserRole } = useAppContext();

    const handleLogout = async () => {
        try {
            const supabase = createClient();
            await supabase.auth.signOut();
            setUserRole(null);
            window.location.href = '/';
        } catch {
            console.error("Error cerrando sesión");
        }
    };

    return (
        <button
            onClick={handleLogout}
            className="w-full mt-2 bg-red-900/20 text-red-500 py-2 rounded border border-red-900/50 hover:bg-red-500 hover:text-white transition flex items-center justify-center gap-2"
        >
            <i className="fas fa-sign-out-alt"></i> Cerrar Sesión Segura
        </button>
    );
}

import { createServerClient } from '@supabase/ssr';
import { NextResponse, type NextRequest } from 'next/server';

export async function updateSession(request: NextRequest) {
    let supabaseResponse = NextResponse.next({
        request,
    });

    const supabase = createServerClient(
        process.env.NEXT_PUBLIC_SUPABASE_URL!,
        process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY!,
        {
            cookies: {
                getAll() {
                    return request.cookies.getAll();
                },
                setAll(cookiesToSet) {
                    cookiesToSet.forEach(({ name, value, options }) => request.cookies.set(name, value));
                    supabaseResponse = NextResponse.next({
                        request,
                    });
                    cookiesToSet.forEach(({ name, value, options }) =>
                        supabaseResponse.cookies.set(name, value, options)
                    );
                },
            },
        }
    );

    const {
        data: { user },
    } = await supabase.auth.getUser();

    const { pathname } = request.nextUrl;

    // RUTAS PROTEGIDAS /admin
    if (pathname.startsWith('/admin')) {
        if (!user || user.email !== 'greciafashionstore2@gmail.com') {
            return NextResponse.redirect(new URL('/', request.url));
        }
    }

    // RUTAS PROTEGIDAS /user
    if (pathname.startsWith('/user')) {
        if (!user) {
            return NextResponse.redirect(new URL('/', request.url));
        }
    }

    return supabaseResponse;
}
